/**
 * TypeScript 类型定义
 * 电商平台 - 用户登录注册、商品列表、商品详情、购物车、订单管理、结算页面
 */

// ==================== 用户相关 ====================

/** 用户信息 */
export interface User {
  id: string;
  username: string;
  email: string;
  avatar?: string;
  phone?: string;
  createdAt: string;
}

/** 登录请求 */
export interface LoginRequest {
  username: string;
  password: string;
}

/** 注册请求 */
export interface RegisterRequest {
  username: string;
  email: string;
  password: string;
  confirmPassword: string;
}

/** 登录/注册响应 */
export interface AuthResponse {
  success: boolean;
  message: string;
  data?: {
    user: User;
    token: string;
  };
}

// ==================== 商品相关 ====================

/** 商品分类 */
export interface Category {
  id: string;
  name: string;
  slug: string;
  icon?: string;
  parentId: string | null;
  children?: Category[];
}

/** 商品 SKU 规格 */
export interface SkuSpec {
  name: string;   // 规格名，如 "颜色"
  value: string;  // 规格值，如 "红色"
}

/** 商品 SKU */
export interface Sku {
  id: string;
  productId: string;
  specs: SkuSpec[];
  price: number;
  stock: number;
  image?: string;
  skuCode: string;
}

/** 商品 */
export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  originalPrice?: number;       // 原价/划线价
  images: string[];
  categoryId: string;
  category?: Category;
  skus: Sku[];
  tags: string[];
  sales: number;                // 销量
  rating: number;               // 评分 1-5
  reviewCount: number;          // 评价数
  isOnSale: boolean;            // 是否在售
  isFeatured: boolean;          // 是否推荐
  stock: number;                // 总库存
  createdAt: string;
  updatedAt: string;
}

/** 商品列表查询参数 */
export interface ProductQueryParams {
  keyword?: string;
  categoryId?: string;
  sortBy?: 'price_asc' | 'price_desc' | 'sales' | 'rating' | 'newest';
  minPrice?: number;
  maxPrice?: number;
  page?: number;
  pageSize?: number;
  tags?: string[];
}

/** 商品列表响应 */
export interface ProductListResponse {
  items: Product[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

// ==================== 购物车相关 ====================

/** 购物车单项 */
export interface CartItem {
  id: string;              // 唯一标识（可基于 productId + skuId 生成）
  productId: string;
  skuId: string;
  product: Product;
  sku: Sku;
  quantity: number;
  checked: boolean;        // 是否勾选（结算用）
  addedAt: string;
}

/** 购物车 */
export interface Cart {
  items: CartItem[];
  totalCount: number;       // 商品总数量
  totalCheckedCount: number;// 已勾选数量
  totalPrice: number;       // 已勾选商品总价
}

// ==================== 地址相关 ====================

/** 收货地址 */
export interface Address {
  id: string;
  userId: string;
  receiverName: string;
  receiverPhone: string;
  province: string;
  city: string;
  district: string;
  detail: string;
  zipCode?: string;
  isDefault: boolean;
}

// ==================== 订单相关 ====================

/** 订单状态 */
export enum OrderStatus {
  PENDING_PAYMENT = 'pending_payment',
  PENDING_SHIPMENT = 'pending_shipment',
  SHIPPED = 'shipped',
  DELIVERED = 'delivered',
  COMPLETED = 'completed',
  CANCELLED = 'cancelled',
  REFUNDING = 'refunding',
  REFUNDED = 'refunded',
}

/** 订单状态中文映射 */
export const OrderStatusLabel: Record<OrderStatus, string> = {
  [OrderStatus.PENDING_PAYMENT]: '待付款',
  [OrderStatus.PENDING_SHIPMENT]: '待发货',
  [OrderStatus.SHIPPED]: '已发货',
  [OrderStatus.DELIVERED]: '已送达',
  [OrderStatus.COMPLETED]: '已完成',
  [OrderStatus.CANCELLED]: '已取消',
  [OrderStatus.REFUNDING]: '退款中',
  [OrderStatus.REFUNDED]: '已退款',
};

/** 订单商品项 */
export interface OrderItem {
  id: string;
  productId: string;
  skuId: string;
  productName: string;
  productImage: string;
  skuSpecs: SkuSpec[];
  price: number;          // 下单时单价
  quantity: number;
  subtotal: number;       // 小计
}

/** 订单 */
export interface Order {
  id: string;
  orderNo: string;            // 订单编号
  userId: string;
  items: OrderItem[];
  totalAmount: number;        // 商品总价
  freight: number;            // 运费
  discountAmount: number;     // 优惠金额
  finalAmount: number;        // 实付金额
  status: OrderStatus;
  address: Address;           // 收货地址快照
  remark?: string;            // 备注
  createdAt: string;
  updatedAt: string;
  paidAt?: string;
  shippedAt?: string;
  deliveredAt?: string;
  completedAt?: string;
  cancelledAt?: string;
}

/** 订单查询参数 */
export interface OrderQueryParams {
  status?: OrderStatus;
  keyword?: string;
  page?: number;
  pageSize?: number;
}

/** 订单列表响应 */
export interface OrderListResponse {
  items: Order[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

/** 结算请求 */
export interface CheckoutRequest {
  cartItemIds: string[];      // 要结算的购物车项ID列表
  addressId: string;          // 收货地址ID
  remark?: string;
}

/** 结算响应 */
export interface CheckoutResponse {
  success: boolean;
  message: string;
  data?: {
    order: Order;
  };
}

// ==================== 通用类型 ====================

/** 分页参数 */
export interface PaginationParams {
  page: number;
  pageSize: number;
}

/** 通用 API 响应 */
export interface ApiResponse<T = unknown> {
  success: boolean;
  message: string;
  data?: T;
}

/** 通用分页响应 */
export interface PaginatedResponse<T> {
  items: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

// ==================== Store 状态类型 ====================

/** 认证 Store 状态 */
export interface AuthState {
  user: User | null;
  token: string | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  error: string | null;
  login: (data: LoginRequest) => Promise<void>;
  register: (data: RegisterRequest) => Promise<void>;
  logout: () => void;
  clearError: () => void;
}

/** 商品 Store 状态 */
export interface ProductState {
  products: Product[];
  currentProduct: Product | null;
  categories: Category[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
  isLoading: boolean;
  error: string | null;
  queryParams: ProductQueryParams;
  fetchProducts: (params?: ProductQueryParams) => Promise<void>;
  fetchProductById: (id: string) => Promise<void>;
  fetchCategories: () => Promise<void>;
  setQueryParams: (params: Partial<ProductQueryParams>) => void;
}

/** 购物车 Store 状态 */
export interface CartState {
  items: CartItem[];
  totalCount: number;
  totalCheckedCount: number;
  totalPrice: number;
  addToCart: (product: Product, sku: Sku, quantity?: number) => void;
  removeFromCart: (itemId: string) => void;
  updateQuantity: (itemId: string, quantity: number) => void;
  toggleCheck: (itemId: string) => void;
  toggleCheckAll: (checked: boolean) => void;
  clearCart: () => void;
  clearCheckedItems: () => void;
  getCheckedItems: () => CartItem[];
}

/** 订单 Store 状态 */
export interface OrderState {
  orders: Order[];
  currentOrder: Order | null;
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
  isLoading: boolean;
  error: string | null;
  fetchOrders: (params?: OrderQueryParams) => Promise<void>;
  fetchOrderById: (id: string) => Promise<void>;
  createOrder: (data: CheckoutRequest) => Promise<CheckoutResponse>;
  cancelOrder: (id: string) => Promise<void>;
  payOrder: (id: string) => Promise<void>;
}

/** 地址 Store 状态 */
export interface AddressState {
  addresses: Address[];
  currentAddress: Address | null;
  isLoading: boolean;
  error: string | null;
  fetchAddresses: () => Promise<void>;
  addAddress: (address: Omit<Address, 'id' | 'userId'>) => Promise<void>;
  updateAddress: (id: string, address: Partial<Address>) => Promise<void>;
  deleteAddress: (id: string) => Promise<void>;
  setDefaultAddress: (id: string) => Promise<void>;
}

// ==================== 路由类型 ====================

/** 路由配置 */
export interface RouteConfig {
  path: string;
  element: React.LazyExoticComponent<React.ComponentType> | React.ComponentType;
  auth?: boolean;       // 是否需要登录
  layout?: boolean;     // 是否使用布局
  children?: RouteConfig[];
}

import { create } from 'zustand';

