const allCategories = ['电子产品', '箱包', '食品', '家居', '服饰'];

// ============================================================
// Store Implementation
// ============================================================

export const useProductStore = create<ProductState>((set, get) => ({
  // Initial State
  products: [],
  selectedProduct: null,
  categories: allCategories,
  loading: false,
  error: null,
  filters: {
    searchQuery: '',
    category: '',
    sortBy: 'newest',
    priceRange: null,
  },

  // Fetch all products
  fetchProducts: async () => {
    set({ loading: true, error: null });
    try {
      // Simulate API call
      await new Promise((resolve) => setTimeout(resolve, 500));
      set({ products: mockProducts, loading: false });
    } catch {
      set({ error: '获取商品列表失败，请稍后重试', loading: false });
    }
  },

  // Fetch single product by ID
  fetchProductById: async (id: string) => {
    set({ loading: true, error: null });
    try {
      await new Promise((resolve) => setTimeout(resolve, 300));
      const product = mockProducts.find((p) => p.id === id) || null;
      if (!product) {
        set({ error: '商品不存在', loading: false, selectedProduct: null });
        return;
      }
      set({ selectedProduct: product, loading: false });
    } catch {
      set({ error: '获取商品详情失败，请稍后重试', loading: false });
    }
  },

  // Set selected product directly
  setSelectedProduct: (product: Product | null) => {
    set({ selectedProduct: product });
  },

  // Filter actions
  setSearchQuery: (query: string) => {
    set((state) => ({
      filters: { ...state.filters, searchQuery: query },
    }));
  },

  setCategory: (category: string) => {
    set((state) => ({
      filters: { ...state.filters, category },
    }));
  },

  setSortBy: (sortBy: ProductFilters['sortBy']) => {
    set((state) => ({
      filters: { ...state.filters, sortBy },
    }));
  },

  setPriceRange: (range: [number, number] | null) => {
    set((state) => ({
      filters: { ...state.filters, priceRange: range },
    }));
  },

  clearFilters: () => {
    set({
      filters: {
        searchQuery: '',
        category: '',
        sortBy: 'newest',
        priceRange: null,
      },
    });
  },

  clearError: () => {
    set({ error: null });
  },

  // Computed: get filtered & sorted products
  getFilteredProducts: () => {
    const { products, filters } = get();
    let result = [...products];

    // Filter by search query
    if (filters.searchQuery.trim()) {
      const q = filters.searchQuery.toLowerCase();
      result = result.filter(
        (p) =>
          p.name.toLowerCase().includes(q) ||
          p.description.toLowerCase().includes(q) ||
          p.tags.some((tag) => tag.toLowerCase().includes(q))
      );
    }

    // Filter by category
    if (filters.category) {
      result = result.filter((p) => p.category === filters.category);
    }

    // Filter by price range
    if (filters.priceRange) {
      const [min, max] = filters.priceRange;
      result = result.filter((p) => p.price >= min && p.price <= max);
    }

    // Sort
    switch (filters.sortBy) {
      case 'price-asc':
        result.sort((a, b) => a.price - b.price);
        break;
      case 'price-desc':
        result.sort((a, b) => b.price - a.price);
        break;
      case 'rating':
        result.sort((a, b) => b.rating - a.rating);
        break;
      case 'newest':
      default:
        result.sort(
          (a, b) =>
            new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
        );
        break;
    }

    return result;
  },

  // Get product by ID from store
  getProductById: (id: string) => {
    return get().products.find((p) => p.id === id);
  },
}));

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

// ============================================================
// Type Definitions
// ============================================================

export interface CartItem {
  /** Unique cart entry ID */
  cartItemId: string;
  /** Product reference */
  productId: string;
  /** Denormalized product name for display */
  name: string;
  /** Denormalized product image */
  image: string;
  /** Unit price at the time of adding to cart */
  price: number;
  /** Quantity in cart */
  quantity: number;
  /** Available stock (used for validation) */
  maxStock: number;
  /** Timestamp when item was added */
  addedAt: string;
}

export interface CartSummary {
  subtotal: number;
  discount: number;
  shipping: number;
  total: number;
  itemCount: number;
}

// ============================================================
// Store State
// ============================================================

interface CartState {
  // Data
  items: CartItem[];

  // UI State
  isCartOpen: boolean;
  lastAddedProductId: string | null;

  // Coupon
  appliedCoupon: string | null;
  couponDiscount: number;

  // Actions - Cart Management
  addItem: (
    productId: string,
    name: string,
    price: number,
    image: string,
    maxStock: number,
    quantity?: number
  ) => void;
  removeItem: (cartItemId: string) => void;
  updateQuantity: (cartItemId: string, quantity: number) => void;
  clearCart: () => void;

  // Actions - Coupon
  applyCoupon: (code: string) => boolean;
  removeCoupon: () => void;

  // Actions - UI
  toggleCart: () => void;
  openCart: () => void;
  closeCart: () => void;
  clearLastAdded: () => void;

  // Computed Helpers
  getCartSummary: () => CartSummary;
  getItemByProductId: (productId: string) => CartItem | undefined;
  getCartCount: () => number;
  isInCart: (productId: string) => boolean;
}

// ============================================================
// Helper: Generate unique cart item ID
// ============================================================

const generateCartItemId = (): string => {
  return `cart_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
};

// ============================================================
// Valid Coupons
// ============================================================

const VALID_COUPONS: Record<string, { type: 'percentage' | 'fixed'; value: number; minOrder: number; label: string }> = {
  SAVE10: { type: 'percentage', value: 0.1, minOrder: 0, label: '全场9折' },
  SAVE50: { type: 'fixed', value: 50, minOrder: 300, label: '满300减50' },
  NEWUSER: { type: 'percentage', value: 0.15, minOrder: 0, label: '新用户85折' },
};

// ============================================================
// Store Implementation
// ============================================================

export const useCartStore = create<CartState>()(
  persist(
    (set, get) => ({
      // Initial State
      items: [],
      isCartOpen: false,
      lastAddedProductId: null,
      appliedCoupon: null,
      couponDiscount: 0,

      // --------------------------------------------------
      // Cart Management
      // --------------------------------------------------

      addItem: (productId, name, price, image, maxStock, quantity = 1) => {
        set((state) => {
          const existingItem = state.items.find(
            (item) => item.productId === productId
          );

          if (existingItem) {
            // Update quantity, but don't exceed stock
            const newQuantity = Math.min(
              existingItem.quantity + quantity,
              maxStock
            );
            return {
              items: state.items.map((item) =>
                item.productId === productId
                  ? { ...item, quantity: newQuantity }
                  : item
              ),
              lastAddedProductId: productId,
            };
          }

          // Add new item
          const newItem: CartItem = {
            cartItemId: generateCartItemId(),
            productId,
            name,
            price,
            image,
            quantity: Math.min(quantity, maxStock),
            maxStock,
            addedAt: new Date().toISOString(),
          };

          return {
            items: [...state.items, newItem],
            lastAddedProductId: productId,
          };
        });
      },

      removeItem: (cartItemId: string) => {
        set((state) => ({
          items: state.items.filter((item) => item.cartItemId !== cartItemId),
        }));
      },

      updateQuantity: (cartItemId: string, quantity: number) => {
        if (quantity < 1) {
          // Remove item if quantity drops below 1
          get().removeItem(cartItemId);
          return;
        }

        set((state) => ({
          items: state.items.map((item) =>
            item.cartItemId === cartItemId
              ? { ...item, quantity: Math.min(quantity, item.maxStock) }
              : item
          ),
        }));
      },

      clearCart: () => {
        set({
          items: [],
          appliedCoupon: null,
          couponDiscount: 0,
          lastAddedProductId: null,
        });
      },

      // --------------------------------------------------
      // Coupon
      // --------------------------------------------------

      applyCoupon: (code: string): boolean => {
        const normalizedCode = code.trim().toUpperCase();
        const coupon = VALID_COUPONS[normalizedCode];

        if (!coupon) {
          return false;
        }

        const { subtotal } = get().getCartSummary();

        if (subtotal < coupon.minOrder) {
          return false;
        }

        let discount = 0;
        if (coupon.type === 'percentage') {
          discount = Math.round(subtotal * coupon.value * 100) / 100;
        } else {
          discount = coupon.value;
        }

        set({
          appliedCoupon: normalizedCode,
          couponDiscount: Math.min(discount, subtotal),
        });

        return true;
      },

      removeCoupon: () => {
        set({ appliedCoupon: null, couponDiscount: 0 });
      },

      // --------------------------------------------------
      // UI Actions
      // --------------------------------------------------

      toggleCart: () => {
        set((state) => ({ isCartOpen: !state.isCartOpen }));
      },

      openCart: () => {
        set({ isCartOpen: true });
      },

      closeCart: () => {
        set({ isCartOpen: false });
      },

      clearLastAdded: () => {
        set({ lastAddedProductId: null });
      },

      // --------------------------------------------------
      // Computed Helpers
      // --------------------------------------------------

      getCartSummary: (): CartSummary => {
        const { items, couponDiscount } = get();

        const subtotal = items.reduce(
          (sum, item) => sum + item.price * item.quantity,
          0
        );

        const itemCount = items.reduce((count, item) => count + item.quantity, 0);

        // Free shipping for orders over 199
        const shipping = subtotal >= 199 || subtotal === 0 ? 0 : 15;

        const discount = couponDiscount;
        const total = Math.max(0, subtotal - discount + shipping);

        return {
          subtotal: Math.round(subtotal * 100) / 100,
          discount: Math.round(discount * 100) / 100,
          shipping,
          total: Math.round(total * 100) / 100,
          itemCount,
        };
      },

      getItemByProductId: (productId: string): CartItem | undefined => {
        return get().items.find((item) => item.productId === productId);
      },

      getCartCount: (): number => {
        return get().items.reduce((count, item) => count + item.quantity, 0);
      },

      isInCart: (productId: string): boolean => {
        return get().items.some((item) => item.productId === productId);
      },
    }),
    {
      name: 'ecommerce-cart',
      partialize: (state) => ({
        items: state.items,
        appliedCoupon: state.appliedCoupon,
        couponDiscount: state.couponDiscount,
      }),
    }
  )
);

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

// ============================================================
// Type Definitions
// ============================================================

export interface User {
  id: string;
  username: string;
  email: string;
  phone: string;
  avatar: string;
  createdAt: string;
}

export interface Address {
  id: string;
  name: string;
  phone: string;
  province: string;
  city: string;
  district: string;
  street: string;
  zipCode: string;
  isDefault: boolean;
}

export interface LoginCredentials {
  email: string;
  password: string;
}

export interface RegisterData {
  username: string;
  email: string;
  password: string;
  confirmPassword: string;
  phone?: string;
}

// ============================================================
// Store State
// ============================================================

interface UserState {
  // Data
  user: User | null;
  token: string | null;
  addresses: Address[];

  // UI State
  loading: boolean;
  error: string | null;
  isAuthenticated: boolean;

  // Auth Actions
  login: (credentials: LoginCredentials) => Promise<boolean>;
  register: (data: RegisterData) => Promise<boolean>;
  logout: () => void;
  clearError: () => void;

  // Profile Actions
  updateProfile: (updates: Partial<Pick<User, 'username' | 'email' | 'phone' | 'avatar'>>) => void;

  // Address Actions
  addAddress: (address: Omit<Address, 'id'>) => void;
  updateAddress: (id: string, updates: Partial<Omit<Address, 'id'>>) => void;
  removeAddress: (id: string) => void;
  setDefaultAddress: (id: string) => void;
}

// ============================================================
// Mock User Database
// ============================================================

const MOCK_USERS: Array<{ email: string; password: string; user: User }> = [
  {
    email: 'demo@shop.com',
    password: 'demo123',
    user: {
      id: 'user_001',
      username: 'Demo用户',
      email: 'demo@shop.com',
      phone: '13800000001',
      avatar: '',
      createdAt: '2025-01-01T00:00:00Z',
    },
  },
];

// ============================================================
// Helpers
// ============================================================

const generateId = (prefix: string): string => {
  return `${prefix}_${Date.now()}_${Math.random().toString(36).substring(2, 7)}`;
};

const generateToken = (): string => {
  return `token_${Date.now()}_${Math.random().toString(36).substring(2, 18)}`;
};

const delay = (ms: number = 600): Promise<void> =>
  new Promise((resolve) => setTimeout(resolve, ms));

// ============================================================
// Validation
// ============================================================

const validateEmail = (email: string): boolean => {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
};

const validatePassword = (password: string): string | null => {
  if (password.length < 6) return '密码长度不能少于6位';
  if (password.length > 32) return '密码长度不能超过32位';
  return null;
};

// ============================================================
// Store Implementation
// ============================================================

export const useUserStore = create<UserState>()(
  persist(
    (set, get) => ({
      // Initial State
      user: null,
      token: null,
      addresses: [],
      loading: false,
      error: null,
      isAuthenticated: false,

      // --------------------------------------------------
      // Auth Actions
      // --------------------------------------------------

      login: async (credentials: LoginCredentials): Promise<boolean> => {
        set({ loading: true, error: null });

        try {
          await delay();

          // Validate input
          if (!credentials.email.trim() || !credentials.password.trim()) {
            set({ error: '请输入邮箱和密码', loading: false });
            return false;
          }

          if (!validateEmail(credentials.email)) {
            set({ error: '邮箱格式不正确', loading: false });
            return false;
          }

          // Check mock database
          const matchedUser = MOCK_USERS.find(
            (u) => u.email === credentials.email && u.password === credentials.password
          );

          if (!matchedUser) {
            // Also allow the demo account to be created on-the-fly
            if (credentials.email === 'demo@shop.com' && credentials.password === 'demo123') {
              const token = generateToken();
              set({
                user: {
                  id: 'user_001',
                  username: 'Demo用户',
                  email: 'demo@shop.com',
                  phone: '13800000001',
                  avatar: '',
                  createdAt: '2025-01-01T00:00:00Z',
                },
                token,
                isAuthenticated: true,
                loading: false,
                error: null,
              });
              return true;
            }

            set({ error: '邮箱或密码错误', loading: false });
            return false;
          }

          const token = generateToken();
          set({
            user: matchedUser.user,
            token,
            isAuthenticated: true,
            loading: false,
            error: null,
          });

          return true;
        } catch {
          set({ error: '登录失败，请稍后重试', loading: false });
          return false;
        }
      },

      register: async (data: RegisterData): Promise<boolean> => {
        set({ loading: true, error: null });

        try {
          await delay();

          // Validate input
          if (!data.username.trim()) {
            set({ error: '请输入用户名', loading: false });
            return false;
          }

          if (!validateEmail(data.email)) {
            set({ error: '邮箱格式不正确', loading: false });
            return false;
          }

          const passwordError = validatePassword(data.password);
          if (passwordError) {
            set({ error: passwordError, loading: false });
            return false;
          }

          if (data.password !== data.confirmPassword) {
            set({ error: '两次输入的密码不一致', loading: false });
            return false;
          }

          // Check if email already exists
          if (MOCK_USERS.some((u) => u.email === data.email)) {
            set({ error: '该邮箱已被注册', loading: false });
            return false;
          }

          // Create new user
          const newUser: User = {
            id: generateId('user'),
            username: data.username.trim(),
            email: data.email.trim(),
            phone: data.phone?.trim() || '',
            avatar: '',
            createdAt: new Date().toISOString(),
          };

          const token = generateToken();

          // Add to mock database (in-memory)
          MOCK_USERS.push({
            email: data.email,
            password: data.password,
            user: newUser,
          });

          set({
            user: newUser,
            token,
            isAuthenticated: true,
            loading: false,
            error: null,
          });

          return true;
        } catch {
          set({ error: '注册失败，请稍后重试', loading: false });
          return false;
        }
      },

      logout: () => {
        set({
          user: null,
          token: null,
          isAuthenticated: false,
          addresses: [],
          error: null,
          loading: false,
        });
      },

      clearError: () => {
        set({ error: null });
      },

      // --------------------------------------------------
      // Profile Actions
      // --------------------------------------------------

      updateProfile: (updates) => {
        set((state) => {
          if (!state.user) return state;
          return {
            user: { ...state.user, ...updates },
          };
        });
      },

      // --------------------------------------------------
      // Address Actions
      // --------------------------------------------------

      addAddress: (addressData) => {
        const newAddress: Address = {
          ...addressData,
          id: generateId('addr'),
        };

        set((state) => {
          // If this is the first address or marked as default, unset others
          if (newAddress.isDefault || state.addresses.length === 0) {
            return {
              addresses: [
                ...state.addresses.map((addr) => ({ ...addr, isDefault: false })),
                { ...newAddress, isDefault: true },
              ],
            };
          }
          return { addresses: [...state.addresses, newAddress] };
        });
      },

      updateAddress: (id, updates) => {
        set((state) => ({
          addresses: state.addresses.map((addr) =>
            addr.id === id ? { ...addr, ...updates } : addr
          ),
        }));
      },

      removeAddress: (id) => {
        set((state) => {
          const filtered = state.addresses.filter((addr) => addr.id !== id);
          // If removed address was default, make the first remaining one default
          if (
            state.addresses.find((a) => a.id === id)?.isDefault &&
            filtered.length > 0
          ) {
            filtered[0] = { ...filtered[0], isDefault: true };
          }
          return { addresses: filtered };
        });
      },

      setDefaultAddress: (id) => {
        set((state) => ({
          addresses: state.addresses.map((addr) => ({
            ...addr,
            isDefault: addr.id === id,
          })),
        }));
      },
    }),
    {
      name: 'ecommerce-user',
      partialize: (state) => ({
        user: state.user,
        token: state.token,
        isAuthenticated: state.isAuthenticated,
        addresses: state.addresses,
      }),
    }
  )
);

import { lazy, Suspense } from 'react';
import { createBrowserRouter, Navigate, Outlet, RouteObject } from 'react-router-dom';
import type { User, Product, CartItem, Order } from '../types';

// Layouts
import MainLayout from '../layouts/MainLayout';
import AuthLayout from '../layouts/AuthLayout';

// Pages - Lazy loaded for better performance
const HomePage = lazy(() => import('../pages/HomePage'));
const LoginPage = lazy(() => import('../pages/LoginPage'));
const RegisterPage = lazy(() => import('../pages/RegisterPage'));
const ProductListPage = lazy(() => import('../pages/ProductListPage'));
const ProductDetailPage = lazy(() => import('../pages/ProductDetailPage'));
const CartPage = lazy(() => import('../pages/CartPage'));
const CheckoutPage = lazy(() => import('../pages/CheckoutPage'));
const OrderListPage = lazy(() => import('../pages/OrderListPage'));
const OrderDetailPage = lazy(() => import('../pages/OrderDetailPage'));
const UserProfilePage = lazy(() => import('../pages/UserProfilePage'));
const NotFoundPage = lazy(() => import('../pages/NotFoundPage'));

// Components
import LoadingSpinner from '../components/LoadingSpinner';
import ProtectedRoute from '../components/ProtectedRoute';

// Route paths
export const Path = {
  HOME: '/',
  LOGIN: '/login',
  REGISTER: '/register',
  PRODUCTS: '/products',
  PRODUCT_DETAIL: '/products/:id',
  CART: '/cart',
  CHECKOUT: '/checkout',
  ORDERS: '/orders',
  ORDER_DETAIL: '/orders/:id',
  PROFILE: '/profile',
  NOT_FOUND: '*',
} as const;

// Suspense fallback component
const PageLoader = () => (
  <div className="flex items-center justify-center min-h-[50vh]">
    <LoadingSpinner size="large" />
  </div>
);

// Auth routes wrapper (for non-authenticated users)
const AuthRoute = ({ children }: { children: React.ReactNode }) => {
  // Check if user is logged in (you may use a hook or context here)
  const isAuthenticated = false; // This should come from auth store

  if (isAuthenticated) {
    return <Navigate to={Path.HOME} replace />;
  }

  return <>{children}</>;
};

// Main content wrapper with layout
const MainContent = () => (
  <MainLayout>
    <Suspense fallback={<PageLoader />}>
      <Outlet />
    </Suspense>
  </MainLayout>
);

// Auth layout wrapper
const AuthContent = () => (
  <AuthLayout>
    <Suspense fallback={<PageLoader />}>
      <Outlet />
    </Suspense>
  </AuthLayout>
);

// Route definitions
const routes: RouteObject[] = [
  // Public routes with main layout
  {
    path: '/',
    element: <MainContent />,
    children: [
      {
        index: true,
        element: <HomePage />,
      },
      {
        path: Path.PRODUCTS,
        element: <ProductListPage />,
      },
      {
        path: Path.PRODUCT_DETAIL,
        element: <ProductDetailPage />,
      },
      // Protected routes
      {
        path: Path.CART,
        element: (
          <ProtectedRoute>
            <CartPage />
          </ProtectedRoute>
        ),
      },
      {
        path: Path.CHECKOUT,
        element: (
          <ProtectedRoute>
            <CheckoutPage />
          </ProtectedRoute>
        ),
      },
      {
        path: Path.ORDERS,
        element: (
          <ProtectedRoute>
            <OrderListPage />
          </ProtectedRoute>
        ),
      },
      {
        path: Path.ORDER_DETAIL,
        element: (
          <ProtectedRoute>
            <OrderDetailPage />
          </ProtectedRoute>
        ),
      },
      {
        path: Path.PROFILE,
        element: (
          <ProtectedRoute>
            <UserProfilePage />
          </ProtectedRoute>
        ),
      },
      {
        path: Path.NOT_FOUND,
        element: <NotFoundPage />,
      },
    ],
  },
  // Auth routes
  {
    path: '/auth',
    element: <AuthContent />,
    children: [
      {
        path: 'login',
        element: (
          <AuthRoute>
            <LoginPage />
          </AuthRoute>
        ),
      },
      {
        path: 'register',
        element: (
          <AuthRoute>
            <RegisterPage />
          </AuthRoute>
        ),
      },
    ],
  },
  // Redirect root to home
  {
    path: '',
    element: <Navigate to={Path.HOME} replace />,
  },
];

// Create router instance
const router = createBrowserRouter(routes, {
  future: {
    v7_startTransition: true,
    v7_relativeSplatPath: true,
    v7_fetcherPersist: true,
    v7_normalizeFormMethod: true,
  },
});

export default router;

