interface CartItemRowProps {
  item: CartItem;
  onToggleSelect: () => void;
  onUpdateQuantity: (quantity: number) => void;
  onRemove: () => void;
}

const CartItemRow: React.FC<CartItemRowProps> = ({
  item,
  onToggleSelect,
  onUpdateQuantity,
  onRemove,
}) => {
  const [showDelete, setShowDelete] = React.useState(false);

  return (
    <div className="p-4 flex gap-4">
      <input
        type="checkbox"
        checked={item.selected}
        onChange={onToggleSelect}
        className="w-5 h-5 rounded text-blue-600 mt-8"
      />
      <Link to={`/products/${item.product.id}`}>
        <img
          src={item.product.image}
          alt={item.product.name}
          className="w-24 h-24 object-cover rounded-lg"
        />
      </Link>
      <div className="flex-1">
        <div className="flex justify-between">
          <Link
            to={`/products/${item.product.id}`}
            className="font-semibold text-gray-800 hover:text-blue-600"
          >
            {item.product.name}
          </Link>
          <button
            onClick={() => setShowDelete(true)}
            className="text-gray-400 hover:text-red-500"
          >
            ✕
          </button>
        </div>
        <p className="text-gray-500 text-sm mt-1">{item.product.category}</p>
        <div className="flex items-center justify-between mt-4">
          <span className="text-lg font-bold text-red-500">
            ¥{item.product.price}
          </span>
          <div className="flex items-center border border-gray-300 rounded-lg">
            <button
              onClick={() => onUpdateQuantity(item.quantity - 1)}
              className="px-3 py-1 text-gray-600 hover:bg-gray-100"
            >
              -
            </button>
            <input
              type="number"
              value={item.quantity}
              onChange={(e) =>
                onUpdateQuantity(
                  Math.max(1, Math.min(item.product.stock, parseInt(e.target.value) || 1))
                )
              }
              className="w-12 text-center border-x border-gray-300 py-1"
            />
            <button
              onClick={() => onUpdateQuantity(item.quantity + 1)}
              className="px-3 py-1 text-gray-600 hover:bg-gray-100"
            >
              +
            </button>
          </div>
        </div>
        <div className="text-gray-500 text-sm mt-2">
          小计: ¥{(item.product.price * item.quantity).toFixed(2)}
        </div>
      </div>

      {/* Delete Confirmation Modal */}
      {showDelete && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl p-6 max-w-sm w-full mx-4">
            <h3 className="text-lg font-semibold mb-4">确认删除</h3>
            <p className="text-gray-600 mb-6">
              确定要从购物车中删除 "{item.product.name}" 吗？
            </p>
            <div className="flex gap-4">
              <button
                onClick={() => setShowDelete(false)}
                className="flex-1 py-2 border border-gray-300 rounded-lg hover:bg-gray-50"
              >
                取消
              </button>
              <button
                onClick={() => {
                  onRemove();
                  setShowDelete(false);
                }}
                className="flex-1 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600"
              >
                删除
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Cart;

