import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useOrderStore } from '../store/useOrderStore';
import { useAuthStore } from '../store/useAuthStore';
import type { Order } from '../types';

const Orders: React.FC = () => {
  const navigate = useNavigate();
  const { orders, cancelOrder } = useOrderStore();
  const { isAuthenticated } = useAuthStore();
  const [activeTab, setActiveTab] = useState<
    'all' | 'pending' | 'paid' | 'shipped' | 'delivered'
  >('all');

  React.useEffect(() => {
    if (!isAuthenticated) {
      if (confirm('请先登录，是否前往登录？')) {
        navigate('/auth');
      }
    }
  }, [isAuthenticated, navigate]);

  const filteredOrders = orders.filter((order) => {
    if (activeTab === 'all') return true;
    if (activeTab === 'pending') return order.status === 'pending';
    if (activeTab === 'paid') return order.status === 'paid';
    if (activeTab === 'shipped') return order.status === 'shipped';
    if (activeTab === 'delivered') return order.status === 'delivered';
    return true;
  });

  const getStatusText = (status: Order['status']) => {
    const statusMap = {
      pending: { text: '待支付', color: 'bg-orange-100 text-orange-600' },
      paid: { text: '已支付', color: 'bg-blue-100 text-blue-600' },
      shipped: { text: '已发货', color: 'bg-purple-100 text-purple-600' },
      delivered: { text: '已完成', color: 'bg-green-100 text-green-600' },
      cancelled: { text: '已取消', color: 'bg-gray-100 text-gray-600' },
    };
    return statusMap[status];
  };

  if (!isAuthenticated) {
    return null;
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <Link to="/" className="text-2xl font-bold text-blue-600">
              🛒 电商平台
            </Link>
            <nav className="flex items-center gap-6">
              <Link to="/" className="text-gray-600 hover:text-blue-600">
                首页
              </Link>
              <Link to="/products" className="text-gray-600 hover:text-blue-600">
                商品列表
              </Link>
              <Link to="/cart" className="text-gray-600 hover:text-blue-600">
                购物车
              </Link>
              <span className="text-blue-600 font-medium">我的订单</span>
            </nav>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6">
        <h1 className="text-2xl font-bold mb-6">我的订单</h1>

        {/* Tabs */}
        <div className="bg-white rounded-xl shadow-sm mb-6">
          <div className="flex overflow-x-auto">
            {[
              { key: 'all', label: '全部订单' },
              { key: 'pending', label: '待支付' },
              { key: 'paid', label: '已支付' },
              { key: 'shipped', label: '已发货' },
              { key: 'delivered', label: '已完成' },
            ].map((tab) => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key as typeof activeTab)}
                className={`px-6 py-4 font-medium whitespace-nowrap border-b-2 transition ${
                  activeTab === tab.key
                    ? 'border-blue-600 text-blue-600'
                    : 'border-transparent text-gray-600 hover:text-gray-800'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        {/* Orders List */}
        {filteredOrders.length === 0 ? (
          <div className="bg-white rounded-xl shadow-sm p-16 text-center">
            <div className="text-6xl mb-4">📦</div>
            <h3 className="text-xl font-semibold text-gray-600 mb-2">
              暂无订单
            </h3>
            <p className="text-gray-400 mb-6">快去选购心仪的商品吧</p>
            <Link
              to="/products"
              className="inline-block px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
            >
              去购物
            </Link>
          </div>
        ) : (
          <div className="space-y-4">
            {filteredOrders.map((order) => (
              <div key={order.id} className="bg-white rounded-xl shadow-sm overflow-hidden">
                {/* Order Header */}
                <div className="flex items-center justify-between px-6 py-4 bg-gray-50 border-b">
                  <div className="flex items-center gap-6">
                    <span className="text-gray-500">
                      订单号: {order.orderNumber}
                    </span>
                    <span className="text-gray-400">
                      {new Date(order.createdAt).toLocaleDateString('zh-CN')}
                    </span>
                  </div>
                  <span
                    className={`px-3 py-1 rounded-full text-sm font-medium ${getStatusText(order.status).color}`}
                  >
                    {getStatusText(order.status).text}
                  </span>
                </div>

                {/* Order Items */}
                <div className="p-6">
                  <div className="space-y-4">
                    {order.items.map((item) => (
                      <div key={item.id} className="flex gap-4">
                        <Link to={`/products/${item.product.id}`}>
